// Создание кнопки с обработкой клика
Button {
    id: myButton
    text: "Нажми меня"
    width: 150
    height: 40

    // Обработчик клика с JS логикой
    onClicked: {
        console.log("Кнопка нажата в " + new Date().toLocaleTimeString());
        text = "Нажато! ✓";

        // Возвращаем исходный текст через 1 секунду
        Qt.callLater(() => {
            setTimeout(() => text = "Нажми меня", 1000);
        });
    }

    // Изменение стиля при наведении
    background: Rectangle {
        color: myButton.hovered ? "#4CAF50" : "#2196F3"
        radius: 5
    }
}

// Текстовое поле с валидацией
TextField {
    id: nameField
    placeholderText: "Введите ваше имя..."
    width: 200

    // Валидация при изменении текста
    onTextChanged: {
        if(text.length === 0) {
            console.log("Поле пустое");
            border.color = "gray";
        } else if(text.length < 3) {
            console.warn("Имя слишком короткое");
            border.color = "orange";
        } else if(text.length > 20) {
            console.error("Имя слишком длинное!");
            border.color = "red";
            text = text.substring(0, 20); // Обрезаем
        } else {
            console.log("Валидное имя: " + text);
            border.color = "green";
        }
    }

    // Обработка нажатия Enter
    onAccepted: {
        console.log("Введено имя: " + text);
        Qt.inputMethod.hide(); // Скрыть клавиатуру
    }

    border.width: 2
    border.color: "gray"
}

// Ползунок с отображением значения
Slider {
    id: volumeSlider
    from: 0
    to: 100
    value: 50
    stepSize: 1
    width: 200

    // Обработка изменения значения
    onMoved: {
        console.log("Громкость: " + value.toFixed(0) + "%");

        // Динамическое обновление связанных элементов
        if(parent.volumeText) {
            parent.volumeText.text = value.toFixed(0) + "%";
        }

        // Пример: изменение прозрачности
        parent.opacity = 0.5 + (value / 200);
    }

    // Настройка внешнего вида
    background: Rectangle {
        color: "lightgray"
        height: 4
        radius: 2
    }

    handle: Rectangle {
        width: 20
        height: 20
        radius: 10
        color: volumeSlider.pressed ? "#2196F3" : "white"
        border.width: 2
        border.color: "#2196F3"
    }
}

// CheckBox с зависимыми элементами
CheckBox {
    id: termsCheckbox
    text: "Я согласен с условиями использования"
    checked: false

    // Обработка изменения состояния
    onClicked: {
        console.log("CheckBox изменен: " + (checked ? "ВКЛ" : "ВЫКЛ"));

        // Блокировка/разблокировка зависимых элементов
        parent.submitButton.enabled = checked;

        // Анимация изменения
        parent.opacity = checked ? 1.0 : 0.7;

        // Логика для частичного состояния (tristate)
        if(checkState === Qt.PartiallyChecked) {
            console.log("Частично выбран");
        }
    }

    // Стилизация
    indicator: Rectangle {
        width: 20
        height: 20
        radius: 3
        border.width: 2
        border.color: termsCheckbox.checked ? "green" : "gray"
        color: termsCheckbox.checked ? "lightgreen" : "white"

        // Галочка
        Text {
            anchors.centerIn: parent
            text: "✓"
            visible: termsCheckbox.checked
            color: "green"
            font.bold: true
        }
    }
}

// Группа переключателей для выбора опции
Column {
    spacing: 10

    Text {
        text: "Выберите способ оплаты:"
        font.bold: true
    }

    RadioButton {
        id: cardPayment
        text: "Банковская карта"
        checked: true

        onClicked: {
            console.log("Выбрана оплата картой");
            parent.paymentDetails.visible = true;
            parent.paymentDetails.source = "CardForm.qml";
        }
    }

    RadioButton {
        id: cashPayment
        text: "Наличные"

        onClicked: {
            console.log("Выбрана оплата наличными");
            parent.paymentDetails.visible = false;
        }
    }

    RadioButton {
        id: onlinePayment
        text: "Онлайн-кошелек"
        enabled: parent.internetAvailable

        onClicked: {
            console.log("Выбрана онлайн-оплата");
            parent.paymentDetails.visible = true;
            parent.paymentDetails.source = "OnlinePayForm.qml";
        }

        // Стилизация для недоступного состояния
        contentItem: Text {
            text: onlinePayment.text
            color: onlinePayment.enabled ? "black" : "gray"
            font.strikeout: !onlinePayment.enabled
        }
    }
}

// Выпадающий список с динамическим содержимым
ComboBox {
    id: countryCombo
    editable: true
    width: 200

    // Модель данных
    model: ListModel {
        id: countryModel
        ListElement { text: "Россия"; code: "RU" }
        ListElement { text: "США"; code: "US" }
        ListElement { text: "Германия"; code: "DE" }
        ListElement { text: "Япония"; code: "JP" }
        ListElement { text: "Китай"; code: "CN" }
    }

    // Текущий выбранный элемент
    currentIndex: 0

    // Обработка выбора
    onActivated: {
        var selected = countryModel.get(index);
        console.log("Выбрана страна: " + selected.text + " (" + selected.code + ")");

        // Обновление связанных данных
        parent.countryCode = selected.code;

        // Загрузка дополнительных данных
        loadCities(selected.code);
    }

    // Обработка ввода пользователя (в режиме редактирования)
    onAccepted: {
        if(find(currentText) === -1) {
            console.log("Добавлена новая страна: " + currentText);
            countryModel.append({text: currentText, code: "CUSTOM"});
            currentIndex = find(currentText);
        }
    }

    // Кастомизация отображения элементов
    delegate: ItemDelegate {
        width: countryCombo.width
        text: model.text
        highlighted: countryCombo.highlightedIndex === index

        // Иконка флага
        Image {
            anchors.left: parent.left
            anchors.verticalCenter: parent.verticalCenter
            anchors.leftMargin: 5
            source: "flags/" + model.code + ".png"
            width: 20; height: 15
            visible: source !== ""
        }
    }
}

// Индикатор загрузки с управлением
Column {
    spacing: 15
    width: 250

    ProgressBar {
        id: determinateProgress
        width: parent.width
        from: 0
        to: 100
        value: 0
        visible: !indeterminateProgress.visible

        // Стилизация
        background: Rectangle {
            color: "#e0e0e0"
            radius: 3
        }

        contentItem: Item {
            Rectangle {
                width: determinateProgress.visualPosition * parent.width
                height: parent.height
                radius: 3
                gradient: Gradient {
                    GradientStop { position: 0; color: "#4CAF50" }
                    GradientStop { position: 1; color: "#2E7D32" }
                }

                // Анимация заполнения
                Behavior on width {
                    NumberAnimation { duration: 200 }
                }
            }
        }
    }

    ProgressBar {
        id: indeterminateProgress
        width: parent.width
        indeterminate: true
        visible: false

        // Кастомизация неопределенного индикатора
        contentItem: Item {
            Rectangle {
                id: movingBar
                width: 50
                height: parent.height
                radius: 3
                color: "#2196F3"

                // Анимация движения
                SequentialAnimation on x {
                    loops: Animation.Infinite
                    running: indeterminateProgress.visible

                    NumberAnimation {
                        from: 0
                        to: indeterminateProgress.width - movingBar.width
                        duration: 1000
                        easing.type: Easing.InOutQuad
                    }

                    NumberAnimation {
                        from: indeterminateProgress.width - movingBar.width
                        to: 0
                        duration: 1000
                        easing.type: Easing.InOutQuad
                    }
                }
            }
        }
    }

    // Управляющие кнопки
    Row {
        spacing: 10

        Button {
            text: "Начать загрузку"
            onClicked: {
                determinateProgress.value = 0;
                indeterminateProgress.visible = true;

                // Симуляция загрузки
                var interval = setInterval(() => {
                    if(determinateProgress.value < 100) {
                        determinateProgress.value += 10;
                    } else {
                        clearInterval(interval);
                        indeterminateProgress.visible = false;
                        console.log("Загрузка завершена!");
                    }
                }, 300);
            }
        }

        Button {
            text: "Сбросить"
            onClicked: {
                determinateProgress.value = 0;
                indeterminateProgress.visible = false;
            }
        }
    }
}

// Переключатели настроек приложения
Column {
    spacing: 15
    width: 200

    Switch {
        id: notificationsSwitch
        text: "Уведомления"
        checked: true

        onClicked: {
            console.log("Уведомления: " + (checked ? "ВКЛ" : "ВЫКЛ"));

            // Сохранение настройки
            settings.setValue("notifications", checked);

            // Включение/выключение зависимых настроек
            parent.soundSwitch.enabled = checked;
            parent.vibrationSwitch.enabled = checked;

            if(!checked) {
                parent.soundSwitch.checked = false;
                parent.vibrationSwitch.checked = false;
            }
        }

        // Стилизация
        indicator: Rectangle {
            width: 50
            height: 28
            radius: 14
            color: notificationsSwitch.checked ? "#4CAF50" : "#cccccc"
            border.color: notificationsSwitch.checked ? "#388E3C" : "#999999"

            Rectangle {
                x: notificationsSwitch.checked ? parent.width - width - 2 : 2
                y: 2
                width: 24
                height: 24
                radius: 12
                color: "white"
                border.width: 1
                border.color: "#dddddd"

                Behavior on x {
                    NumberAnimation { duration: 150 }
                }
            }
        }
    }

    Switch {
        id: soundSwitch
        text: "Звук уведомлений"
        checked: true
        enabled: notificationsSwitch.checked

        onClicked: {
            console.log("Звук уведомлений: " + (checked ? "ВКЛ" : "ВЫКЛ"));
            settings.setValue("sound", checked);

            // Воспроизведение тестового звука
            if(checked) {
                notificationSound.play();
            }
        }

        // Полупрозрачность при выключении
        opacity: enabled ? 1.0 : 0.5
    }

    Switch {
        id: darkModeSwitch
        text: "Темная тема"
        checked: false

        onClicked: {
            console.log("Темная тема: " + (checked ? "ВКЛ" : "ВЫКЛ"));

            // Применение темы
            applyTheme(checked ? "dark" : "light");

            // Анимация перехода
            parent.themeTransition.running = true;
        }
    }

    // Текст статуса
    Text {
        width: parent.width
        wrapMode: Text.WordWrap
        text: {
            var status = [];
            if(notificationsSwitch.checked) {
                status.push("🔔 Уведомления включены");
                if(soundSwitch.checked) status.push("с звуком");
                if(vibrationSwitch.checked) status.push("с вибрацией");
            } else {
                status.push("🔕 Уведомления выключены");
            }
            status.push(darkModeSwitch.checked ? "🌙 Темная тема" : "☀️ Светлая тема");
            return status.join("\n");
        }
        font.pixelSize: 12
        color: "gray"
    }
}

// Вертикальная компоновка с динамическими элементами
Column {
    id: verticalLayout
    spacing: 10
    padding: 15
    width: 200

    // Свойство для хранения состояния
    property int itemCount: 3

    // Заголовок
    Text {
        text: "Вертикальная компоновка"
        font.bold: true
        color: "#2c3e50"
    }

    // Динамическое создание элементов через JS
    Component.onCompleted: {
        for(var i = 0; i < itemCount; i++) {
            var btn = Qt.createQmlObject(`
                Button {
                    text: "Элемент ${i + 1}"
                    width: parent.width
                    onClicked: console.log("Нажата кнопка ${i + 1}")
                }
            `, verticalLayout);
        }
    }

    // Кнопка для добавления новых элементов
    Button {
        text: "Добавить элемент"
        width: parent.width
        onClicked: {
            itemCount++;
            var btn = Qt.createQmlObject(`
                Button {
                    text: "Новый ${itemCount}"
                    width: parent.width
                    onClicked: console.log("Новая кнопка ${itemCount}")
                }
            `, verticalLayout);
        }
    }
}

// Горизонтальная компоновка с цветными блоками
Row {
    id: horizontalLayout
    spacing: 8
    padding: 10
    height: 60

    // Свойства для управления
    property var colors: ["#FF6B6B", "#4ECDC4", "#45B7D1", "#96CEB4", "#FFEAA7"]
    property var names: ["Красный", "Бирюзовый", "Голубой", "Зеленый", "Желтый"]

    // Динамическое создание цветных блоков
    Component.onCompleted: {
        colors.forEach(function(color, index) {
            var block = Qt.createQmlObject(`
                Rectangle {
                    width: 50
                    height: 50
                    radius: 8
                    color: "${color}"

                    Text {
                        anchors.centerIn: parent
                        text: "${index + 1}"
                        color: "white"
                        font.bold: true
                    }

                    MouseArea {
                        anchors.fill: parent
                        onClicked: console.log("Выбран цвет: ${names[index]}")
                    }
                }
            `, horizontalLayout);
        });
    }

    // Отображение информации
    Text {
        text: "Цвета: " + colors.length
        anchors.verticalCenter: parent.verticalCenter
        color: "#2c3e50"
    }
}

// Табличная компоновка 3x3
Grid {
    id: gridLayout
    columns: 3
    spacing: 5
    width: 165

    // Динамическое создание ячеек таблицы
    Repeater {
        model: 9

        Rectangle {
            id: cell
            width: 50
            height: 50
            color: {
                // Вычисление цвета на основе позиции
                var row = Math.floor(index / 3);
                var col = index % 3;

                if(row === col) return "#FF6B6B"; // Диагональ
                if((row + col) % 2 === 0) return "#4ECDC4"; // Четные
                return "#45B7D1"; // Нечетные
            }
            radius: 5
            border.width: 1
            border.color: "white"

            // Отображение координат
            Text {
                anchors.centerIn: parent
                text: `${Math.floor(index/3)+1},${(index%3)+1}`
                color: "white"
                font.bold: true
            }

            // Обработка клика с JS логикой
            MouseArea {
                anchors.fill: parent
                onClicked: {
                    console.log(`Клик по ячейке [${Math.floor(index/3)+1},${(index%3)+1}]`);

                    // Анимация клика
                    cell.scale = 0.8;
                    cell.color = "#FFEAA7";

                    // Возврат к исходному состоянию
                    setTimeout(() => {
                        cell.scale = 1.0;
                        // Пересчитываем цвет
                        var row = Math.floor(index / 3);
                        var col = index % 3;
                        if(row === col) cell.color = "#FF6B6B";
                        else if((row + col) % 2 === 0) cell.color = "#4ECDC4";
                        else cell.color = "#45B7D1";
                    }, 300);
                }
            }
        }
    }
}

// Навигация между страницами
StackView {
    id: stackView
    width: 300
    height: 200
    initialItem: mainPage

    // Первая страница
    Component {
        id: mainPage

        Rectangle {
            color: "#4ECDC4"

            Column {
                anchors.centerIn: parent
                spacing: 10

                Text {
                    text: "Главная страница"
                    font.bold: true
                    color: "white"
                }

                Button {
                    text: "Перейти на страницу 2"
                    onClicked: {
                        console.log("Переход на страницу 2");
                        stackView.push(secondPage);
                    }
                }
            }
        }
    }

    // Вторая страница
    Component {
        id: secondPage

        Rectangle {
            color: "#FF6B6B"

            Column {
                anchors.centerIn: parent
                spacing: 10

                Text {
                    text: "Страница 2"
                    font.bold: true
                    color: "white"
                }

                Button {
                    text: "Назад"
                    onClicked: {
                        console.log("Возврат на главную");
                        stackView.pop();
                    }
                }

                Button {
                    text: "Добавить ещё страницу"
                    onClicked: {
                        var newPage = Qt.createQmlObject(`
                            Rectangle {
                                color: "#" + Math.floor(Math.random()*16777215).toString(16)
                                Text { anchors.centerIn: parent; text: "Динамическая страница" }
                            }
                        `, stackView);

                        stackView.push(newPage);
                    }
                }
            }
        }
    }
}

// Список пользователей с моделью данных
ListView {
    id: userList
    width: 250
    height: 300
    clip: true

    // Модель данных
    model: ListModel {
        id: userModel
        ListElement { name: "Алексей Иванов"; age: 28; role: "Разработчик"; avatarColor: "#4ECDC4" }
        ListElement { name: "Мария Петрова"; age: 32; role: "Дизайнер"; avatarColor: "#FF6B6B" }
        ListElement { name: "Дмитрий Сидоров"; age: 25; role: "Менеджер"; avatarColor: "#45B7D1" }
    }

    // Делегат для отображения каждого элемента
    delegate: Rectangle {
        id: delegateItem
        width: userList.width
        height: 60
        color: index % 2 === 0 ? "white" : "#f8f9fa"
        border.width: 1
        border.color: "#e9ecef"

        Row {
            anchors.fill: parent
            anchors.margins: 8
            spacing: 12

            // Аватар
            Rectangle {
                width: 40
                height: 40
                radius: 20
                color: avatarColor
                anchors.verticalCenter: parent.verticalCenter

                Text {
                    anchors.centerIn: parent
                    text: name.charAt(0)
                    color: "white"
                    font.bold: true
                }
            }

            // Информация
            Column {
                anchors.verticalCenter: parent.verticalCenter
                spacing: 2

                Text {
                    text: name
                    font.bold: true
                    color: "#2c3e50"
                }

                Text {
                    text: role + ", " + age + " лет"
                    color: "#7f8c8d"
                    font.pixelSize: 12
                }
            }
        }

        // Обработка клика с JS логикой
        MouseArea {
            anchors.fill: parent
            onClicked: {
                console.log("Выбран пользователь: " + name);
                console.log("Данные модели:", model);

                // Подсветка выбранного элемента
                delegateItem.color = "#e3f2fd";
                setTimeout(() => {
                    delegateItem.color = index % 2 === 0 ? "white" : "#f8f9fa";
                }, 300);

                // Динамическое изменение данных
                userModel.setProperty(index, "age", age + 1);
                console.log("Возраст обновлён: " + (age + 1));
            }
        }
    }

    // Кнопка добавления нового пользователя
    Button {
        anchors.bottom: parent.bottom
        anchors.horizontalCenter: parent.horizontalCenter
        text: "Добавить пользователя"
        onClicked: {
            var names = ["Иван", "Ольга", "Сергей", "Екатерина", "Павел"];
            var roles = ["Аналитик", "Тестировщик", "Архитектор", "Админ"];
            var colors = ["#FFEAA7", "#96CEB4", "#DDA0DD", "#FFA07A"];

            var randomName = names[Math.floor(Math.random() * names.length)];
            var randomRole = roles[Math.floor(Math.random() * roles.length)];
            var randomColor = colors[Math.floor(Math.random() * colors.length)];
            var randomAge = Math.floor(Math.random() * 20) + 20;

            userModel.append({
                name: randomName + " Новый",
                age: randomAge,
                role: randomRole,
                avatarColor: randomColor
            });

            console.log("Добавлен новый пользователь: " + randomName);
        }
    }
}

// Использование JavaScript массива как модели
ListView {
    width: 200
    height: 250

    // Массив объектов как модель
    model: {
        // Генерация динамических данных
        var items = [];
        var categories = ["Фрукты", "Овощи", "Напитки", "Сладости"];

        for(var i = 0; i < 15; i++) {
            var category = categories[Math.floor(Math.random() * categories.length)];
            var price = (Math.random() * 100 + 10).toFixed(2);

            items.push({
                name: "Товар " + (i + 1),
                category: category,
                price: price,
                color: category === "Фрукты" ? "#FF6B6B" :
                       category === "Овощи" ? "#4ECDC4" :
                       category === "Напитки" ? "#45B7D1" : "#FFEAA7"
            });
        }

        // Сортировка по категории
        items.sort((a, b) => a.category.localeCompare(b.category));

        return items;
    }

    // Делегат с доступом через modelData
    delegate: Rectangle {
        width: ListView.view.width
        height: 40
        color: modelData.color
        opacity: 0.8

        Row {
            anchors.fill: parent
            anchors.margins: 8
            spacing: 10

            Text {
                text: modelData.name
                color: "white"
                font.bold: true
                width: 80
                elide: Text.ElideRight
            }

            Text {
                text: modelData.category
                color: "white"
                font.pixelSize: 12
                width: 60
                elide: Text.ElideRight
            }

            Text {
                text: modelData.price + " руб."
                color: "white"
                font.bold: true
            }
        }

        MouseArea {
            anchors.fill: parent
            onClicked: {
                console.log("Выбран товар:", modelData);

                // Фильтрация по категории через JS
                var filtered = ListView.view.model.filter(item => 
                    item.category === modelData.category
                );
                console.log("Всего в категории '" + modelData.category + "': " + filtered.length);
            }
        }
    }

    // Заголовок с количеством элементов
    header: Rectangle {
        width: ListView.view.width
        height: 30
        color: "#2c3e50"

        Text {
            anchors.centerIn: parent
            text: "Товары: " + ListView.view.count
            color: "white"
            font.bold: true
        }
    }
}

// Repeater для создания сетки цветов
Column {
    spacing: 15
    padding: 10

    Text {
        text: "Палитра цветов"
        font.bold: true
        color: "#2c3e50"
        font.pixelSize: 16
    }

    // Grid с Repeater
    Grid {
        columns: 5
        spacing: 8
        width: 250

