// Интерактивный квадрат с MouseArea
Rectangle {
    id: interactiveRect
    width: 200
    height: 200
    color: "#4ECDC4"
    radius: 10

    // Свойства для отслеживания состояния
    property int clickCount: 0
    property real startX: 0
    property real startY: 0

    // MouseArea с обработкой всех событий мыши
    MouseArea {
        id: mouseArea
        anchors.fill: parent
        hoverEnabled: true // Включаем отслеживание наведения
        acceptedButtons: Qt.LeftButton | Qt.RightButton | Qt.MiddleButton
        cursorShape: Qt.PointingHandCursor

        // При наведении курсора
        onEntered: {
            console.log("Курсор вошёл в область");
            interactiveRect.scale = 1.05;
            interactiveRect.border.width = 3;
            interactiveRect.border.color = "#2c3e50";
        }

        // При выходе курсора
        onExited: {
            console.log("Курсор вышел из области");
            interactiveRect.scale = 1.0;
            interactiveRect.border.width = 0;
        }

        // При нажатии кнопки мыши
        onPressed: (mouse) => {
            console.log("Нажата кнопка мыши в точке: ", mouse.x, mouse.y);
            startX = mouse.x;
            startY = mouse.y;

            // Определяем какая кнопка нажата
            if(mouse.button === Qt.LeftButton) {
                console.log("Левая кнопка мыши");
                interactiveRect.color = "#FF6B6B";
            } else if(mouse.button === Qt.RightButton) {
                console.log("Правая кнопка мыши");
                interactiveRect.color = "#45B7D1";
            } else if(mouse.button === Qt.MiddleButton) {
                console.log("Средняя кнопка мыши");
                interactiveRect.color = "#96CEB4";
            }
        }

        // При отпускании кнопки мыши
        onReleased: (mouse) => {
            console.log("Кнопка мыши отпущена");
            interactiveRect.color = "#4ECDC4";

            // Проверяем был ли это клик (маленькое перемещение)
            var deltaX = Math.abs(mouse.x - startX);
            var deltaY = Math.abs(mouse.y - startY);

            if(deltaX < 5 && deltaY < 5) {
                clickCount++;
                console.log("Кликов сделано: " + clickCount);

                // Анимация клика
                interactiveRect.rotation += 15;
                setTimeout(() => interactiveRect.rotation -= 15, 150);
            }
        }

        // При двойном клике
        onDoubleClicked: {
            console.log("Двойной клик!");
            interactiveRect.radius = interactiveRect.radius === 10 ? 50 : 10;
        }

        // При перемещении мыши с зажатой кнопкой
        onPositionChanged: (mouse) => {
            if(mouseArea.pressed) {
                console.log("Перетаскивание: ", mouse.x, mouse.y);

                // Можно реализовать drag&drop
                interactiveRect.x += mouse.x - startX;
                interactiveRect.y += mouse.y - startY;
            }
        }

        // При прокрутке колесика
        onWheel: (wheel) => {
            console.log("Прокрутка колесика: ", wheel.angleDelta.y);

            // Изменение размера при прокрутке
            var delta = wheel.angleDelta.y > 0 ? 10 : -10;
            interactiveRect.width = Math.max(50, interactiveRect.width + delta);
            interactiveRect.height = Math.max(50, interactiveRect.height + delta);

            wheel.accepted = true; // Предотвращаем дальнейшую обработку
        }
    }

    // Отображение статистики
    Text {
        anchors.centerIn: parent
        text: "Кликов: " + interactiveRect.clickCount
        color: "white"
        font.bold: true
        font.pixelSize: 16
    }

    // Инструкция
    Text {
        anchors {
            horizontalCenter: parent.horizontalCenter
            bottom: parent.bottom
            bottomMargin: 10
        }
        text: "Кликай, перетаскивай, прокручивай"
        color: "white"
        font.pixelSize: 10
        opacity: 0.8
    }
}

// Прокручиваемая область с содержимым
