                color: "white"
                font.bold: true
            }
        }

        // Генерируем множество элементов
        Repeater {
            model: 20

            Rectangle {
                width: contentColumn.width - 30
                height: 60
                color: index % 2 === 0 ? "#f8f9fa" : "#e9ecef"
                radius: 6
                border.width: 1
                border.color: "#dee2e6"

                Row {
                    anchors.fill: parent
                    anchors.margins: 10
                    spacing: 15

                    // Номер элемента
                    Rectangle {
                        width: 40
                        height: 40
                        radius: 20
                        color: "#4ECDC4"
                        anchors.verticalCenter: parent.verticalCenter

                        Text {
                            anchors.centerIn: parent
                            text: index + 1
                            color: "white"
                            font.bold: true
                        }
                    }

                    // Информация
                    Column {
                        anchors.verticalCenter: parent.verticalCenter
                        spacing: 2

                        Text {
                            text: "Элемент #" + (index + 1)
                            font.bold: true
                            color: "#2c3e50"
                        }

                        Text {
                            text: "Позиция Y: " + (y + flickableArea.contentY).toFixed(0)
                            color: "#7f8c8d"
                            font.pixelSize: 11
                        }
                    }
                }

                // Обработка клика
                MouseArea {
                    anchors.fill: parent
                    onClicked: {
                        console.log("Выбран элемент #" + (index + 1));
                        console.log("Позиция в контенте: " + y);
                        console.log("Видимая позиция: " + (y + flickableArea.contentY));

