                        setTimeout(() => {
                            parent.color = index % 2 === 0 ? "#f8f9fa" : "#e9ecef";
                        }, 300);
                    }
                }
            }
        }
    }

    // Обработчики событий прокрутки
    onContentYChanged: {
        // Можно реализовать parallax эффект или lazy loading
        var scrollPercent = (contentY / (contentHeight - height)) * 100;
        if(!isNaN(scrollPercent)) {
            console.log("Прокручено: " + scrollPercent.toFixed(1) + "%");
        }
    }

    onMovementStarted: {
        console.log("Начало прокрутки");
        flickableArea.opacity = 0.95;
    }

    onMovementEnded: {
        console.log("Конец прокрутки. Позиция Y: " + contentY.toFixed(0));
        flickableArea.opacity = 1.0;

        // Автоматическая подгрузка при достижении конца
        if(contentY >= contentHeight - height - 50) {
            console.log("Достигнут конец, можно подгружать данные...");
        }
    }

    onFlickStarted: {
        console.log("Быстрая прокрутка (flick) начата");
    }

    onFlickEnded: {
        console.log("Быстрая прокрутка завершена");
    }

    // Отображение индикатора прокрутки
    Rectangle {
        anchors {
            right: parent.right
            top: parent.top
            bottom: parent.bottom
            margins: 2
        }
        width: 6
        radius: 3
        color: "#BDC3C7"
        opacity: flickableArea.moving ? 0.8 : 0.3
        visible: contentHeight > height

        Behavior on opacity {
            NumberAnimation { duration: 200 }
        }

        // Бегунок
        Rectangle {
            id: scrollThumb
            width: parent.width
            height: Math.max(20, (flickableArea.height / flickableArea.contentHeight) * parent.height)
            y: (flickableArea.contentY / flickableArea.contentHeight) * (parent.height - height)
            radius: 3
            color: "#2c3e50"

            Behavior on y {
                enabled: !flickableArea.moving
                NumberAnimation { duration: 100 }
            }
        }
    }
}

// Игровой элемент с управлением клавиатурой
Rectangle {
    id: gameArea
    width: 400
    height: 300
    color: "#2c3e50"
    radius: 10
    focus: true // Важно: элемент должен иметь фокус для получения событий клавиатуры

    // Игровой персонаж
    Rectangle {
        id: player
        width: 40
        height: 40
        radius: 20
        color: "#4ECDC4"
        x: parent.width / 2 - width / 2
        y: parent.height / 2 - height / 2

        // Анимация движения
        Behavior on x {
            NumberAnimation { duration: 100; easing.type: Easing.OutCubic }
        }
        Behavior on y {
            NumberAnimation { duration: 100; easing.type: Easing.OutCubic }
        }
    }

    // Цели для сбора
    Repeater {
        model: 5

        Rectangle {
            id: target
            property bool collected: false
            width: 25
            height: 25
            radius: 12.5
            color: collected ? "#FF6B6B" : "#FFEAA7"
            x: Math.random() * (gameArea.width - 30)
            y: Math.random() * (gameArea.height - 30)
            visible: !collected

            // Анимация появления
            ScaleAnimator on scale {
                from: 0; to: 1; duration: 500; running: true
            }
        }
    }

    // Счет
    Text {
        id: scoreText
        anchors {
            top: parent.top
            right: parent.right
            margins: 10
        }
        text: "Счет: 0"
        color: "white"
        font.bold: true
        font.pixelSize: 16
    }

    property int score: 0
    property int speed: 5

    // Обработка нажатий клавиш
    Keys.onPressed: (event) => {
        console.log("Нажата клавиша:", event.key, "Текст:", event.text);

        // Движение стрелками или WASD
        if(event.key === Qt.Key_Left || event.key === Qt.Key_A) {
            console.log("Движение влево");
            player.x = Math.max(0, player.x - speed);
        }
        else if(event.key === Qt.Key_Right || event.key === Qt.Key_D) {
            console.log("Движение вправо");
            player.x = Math.min(gameArea.width - player.width, player.x + speed);
        }
        else if(event.key === Qt.Key_Up || event.key === Qt.Key_W) {
            console.log("Движение вверх");
            player.y = Math.max(0, player.y - speed);
        }
        else if(event.key === Qt.Key_Down || event.key === Qt.Key_S) {
            console.log("Движение вниз");
            player.y = Math.min(gameArea.height - player.height, player.y + speed);
        }

        // Специальные клавиши
        else if(event.key === Qt.Key_Space) {
            console.log("ПРОБЕЛ - специальное действие");
            player.color = player.color === "#4ECDC4" ? "#FF6B6B" : "#4ECDC4";
            speed = 10; // Ускорение
            setTimeout(() => speed = 5, 1000);
        }
        else if(event.key === Qt.Key_Shift) {
            console.log("SHIFT - замедление");
            speed = 2;
        }
        else if(event.key === Qt.Key_Enter || event.key === Qt.Key_Return) {
            console.log("ENTER - рестарт");
            score = 0;
            scoreText.text = "Счет: 0";
            // Сбрасываем все цели
            for(var i = 0; i < 5; i++) {
                var target = gameArea.children[i+3]; // +3 потому что первые 3 элемента: player, repeater, scoreText
                if(target && target.hasOwnProperty("collected")) {
                    target.collected = false;
                    target.x = Math.random() * (gameArea.width - 30);
                    target.y = Math.random() * (gameArea.height - 30);
                }
            }
        }
        else if(event.key === Qt.Key_Escape) {
            console.log("ESC - выход");
            // В реальном приложении здесь мог бы быть выход
            gameArea.color = gameArea.color === "#2c3e50" ? "#34495e" : "#2c3e50";
        }
        else if(event.key >= Qt.Key_0 && event.key <= Qt.Key_9) {
            var number = event.key - Qt.Key_0;
            console.log("Цифра:", number);
            speed = number + 1; // Устанавливаем скорость от 1 до 10
        }

        // Проверка столкновения с целями
        checkCollisions();

        event.accepted = true; // Говорим, что обработали событие
    }

    // При отпускании Shift возвращаем нормальную скорость
    Keys.onReleased: (event) => {
        if(event.key === Qt.Key_Shift) {
            speed = 5;
        }
    }

    // Функция проверки столкновений
    function checkCollisions() {
        for(var i = 0; i < 5; i++) {
            var target = gameArea.children[i+3];
            if(target && !target.collected) {
                // Простая проверка пересечения окружностей
                var dx = (player.x + player.width/2) - (target.x + target.width/2);
                var dy = (player.y + player.height/2) - (target.y + target.height/2);
                var distance = Math.sqrt(dx*dx + dy*dy);

                if(distance < (player.width/2 + target.width/2)) {
                    console.log("Цель собрана!");
                    target.collected = true;
                    score++;
                    scoreText.text = "Счет: " + score;

                    // Визуальный эффект
                    player.scale = 1.2;
                    setTimeout(() => player.scale = 1.0, 200);

                    // Звуковой эффект (имитация)
                    console.log("БИП!");
                }
            }
        }
    }

    // Инструкция
    Column {
        anchors {
            left: parent.left
            bottom: parent.bottom
            margins: 10
        }
        spacing: 5

        Text {
            text: "Управление:"
            color: "white"
            font.bold: true
        }
        Text {
            text: "←→↑↓ или WASD - движение"
            color: "#BDC3C7"
            font.pixelSize: 12
        }
        Text {
            text: "Пробел - ускорение"
            color: "#BDC3C7"
            font.pixelSize: 12
        }
        Text {
            text: "Enter - рестарт"
            color: "#BDC3C7"
            font.pixelSize: 12
        }
    }
}

