                console.log("Элемент сброшен!");
                console.log("Позиция сброса:", drop.x, drop.y);
                console.log("Источник:", drop.source);
                console.log("Данные:", drop.mimeData);

                // Извлекаем данные из mimeData
                var itemName = drop.mimeData["text/plain"];
                var itemData = JSON.parse(drop.mimeData["application/x-item"]);

                // Добавляем в список сброшенных элементов
                targetArea.droppedItems.push({
                    name: itemName,
                    data: itemData,
                    timestamp: new Date().toLocaleTimeString(),
                    position: {x: drop.x, y: drop.y}
                });

                console.log("Сброшено элементов:", targetArea.droppedItems.length);

                // Визуальная обратная связь
                targetArea.border.color = "#96CEB4";
                targetArea.color = "#f0f9f4";

                // Анимация принятия
                dropAcceptAnim.start();

                // Обновляем текст
                updateDropText();

                // Создаем визуальное представление сброшенного элемента
                createDroppedVisual(itemName, drop.x, drop.y);

                // Сбрасываем исходный элемент обратно
                if(drop.source) {
                    drop.source.x = 0;
                    drop.source.y = 0;
                }
            }
        }

        // Анимация принятия элемента
        SequentialAnimation {
            id: dropAcceptAnim
            PropertyAnimation {
                target: targetArea
                property: "scale"
                from: 1.0
                to: 1.03
                duration: 100
            }
            PropertyAnimation {
                target: targetArea
                property: "scale"
                from: 1.03
                to: 1.0
                duration: 100
            }
        }

        // Функция обновления текста
        function updateDropText() {
            if(targetArea.droppedItems.length === 0) {
                dropText.text = "Перетащите сюда элементы";
                dropText.color = "#7f8c8d";
            } else {
                dropText.text = "Сброшено: " + targetArea.droppedItems.length + " элементов";
                dropText.color = "#2c3e50";
            }
        }

        // Функция создания визуального представления сброшенного элемента
        function createDroppedVisual(name, x, y) {
            var visual = Qt.createQmlObject(`
                Rectangle {
                    width: 60
                    height: 30
                    radius: 4
                    color: "#FFEAA7"
                    border.width: 1
                    border.color: "#FDCB6E"
                    x: ${x - 30}
                    y: ${y - 15}

                    Text {
                        anchors.centerIn: parent
                        text: "${name}"
                        color: "#2c3e50"
                        font.pixelSize: 10
                        font.bold: true
                    }

                    // Удаление по клику
                    MouseArea {
                        anchors.fill: parent
                        onClicked: {
                            console.log("Удаление сброшенного элемента");
                            parent.destroy();
                        }
                    }
                }
            `, targetArea);

            // Анимация появления
            visual.scale = 0;
            visual.opacity = 0;

            var appearAnim = Qt.createQmlObject(`
                SequentialAnimation {
                    ParallelAnimation {
                        NumberAnimation {
                            target: visual
                            property: "scale"
                            from: 0
                            to: 1
                            duration: 200
                            easing.type: Easing.OutBack
                        }
                        NumberAnimation {
                            target: visual
                            property: "opacity"
                            from: 0
                            to: 1
                            duration: 200
                        }
                    }
                }
            `, visual);

            appearAnim.start();
        }

        // Кнопка очистки
        Button {
            anchors {
                horizontalCenter: parent.horizontalCenter
                bottom: parent.bottom
                bottomMargin: 10
            }
            text: "Очистить всё"
            onClicked: {
                console.log("Очистка всех сброшенных элементов");
                targetArea.droppedItems = [];
                updateDropText();

                // Удаляем все визуальные элементы кроме текста и кнопки
                for(var i = 0; i < targetArea.children.length; i++) {
                    var child = targetArea.children[i];
                    if(child !== dropText && child !== this) {
                        child.destroy();
                    }
                }
            }
        }
    }
}
